 14→#[derive(Args, Debug)]
 15→pub struct ValidateDescArgs {
 16→    /// Revision (with optional .. notation)
 17→    #[arg(value_name = "REVISION")]
 18→    pub pos_rev: Option<String>,
 19→
 20→    /// Number of commits (per dotted side)
