 45→/// Status of a single commit's ochid validation.
 46→enum CommitStatus {
 47→    Ok,
 48→    Lost,                     // ochid marked as "lost" (unrecoverable)
 49→    None_,                    // ochid marked as "none" (no counterpart)
 50→    NeedsFixed(String),       // summary of issues
 51→    MissingNoTitle,           // no ochid, no title to match on
 52→    MissingNoMatch,           // no ochid, no title match in other repo
 53→    MissingAmbiguous(usize),  // no ochid, multiple title matches
 54→    MissingWithMatch(String), // no ochid, unique title match found
 55→}
 56→
 57→pub fn validate_desc(args: &ValidateDescArgs) -> Result<(), Box<dyn std::error::Error>> {
 58→    let (workspace, repo) = common::load_repo(&args.repo)?;
 59→
 60→    // Resolve other repo: --other-repo flag, or fall back to .vc-config.toml
 61→    let other_repo_path = if let Some(ref p) = args.other_repo {
 62→        p.clone()
 63→    } else {
 64→        let config = toml_simple::toml_load(&args.repo.join(VC_CONFIG_FILE))?;
 65→        PathBuf::from(other_repo_from_config(&config)?)
 66→    };
 67→
 68→    let (other_workspace, other_repo) = common::load_repo(&other_repo_path)?;
 69→    let other_config = toml_simple::toml_load(&other_repo_path.join(VC_CONFIG_FILE))?;
 70→    let other_prefix = ochid_prefix_from_config(&other_config)?;
 71→
 72→    let spec = common::resolve_spec(
 73→        args.pos_rev.as_deref(),
 74→        args.pos_count,
 75→        &args.revision,
 76→        args.limit,
 77→        "@",
 78→    );
 79→
 80→    let (ids, _anchor_index) = common::collect_ids(
 81→        &workspace,
 82→        &repo,
 83→        &spec.rev,
 84→        spec.desc_count,
 85→        spec.anc_count,
 86→    )?;
 87→    if ids.is_empty() {
 88→        return Err(format!("no commits found for revision '{}'", args.revision).into());
 89→    }
 90→
 91→    let root_id = repo.store().root_commit_id().clone();
 92→    let mut valid = 0;
 93→    let mut lost = 0;
 94→    let mut none = 0;
 95→    let mut issues_count = 0;
 96→    let mut missing = 0;
 97→
 98→    let col_header = "STAT CHANGEID      TITLE";
 99→    println!("{col_header}");
100→
101→    for commit_id in &ids {
102→        if *commit_id == root_id {
103→            continue;
104→        }
105→        let commit = repo.store().get_commit(commit_id)?;
106→        let desc = commit.description();
107→        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
108→        let change_short = &change_hex[..change_hex.len().min(12)];
109→        let first_line = desc.lines().next().unwrap_or("");
110→        let display_title = if first_line.is_empty() {
111→            "(no description set)"
112→        } else {
113→            first_line
114→        };
115→
116→        let current_ochid = common::extract_ochid(&commit);
117→
118→        let status = if let Some(ref ochid_val) = current_ochid {
119→            let bare = extract_bare_id(ochid_val);
120→            if bare == "lost" {
121→                CommitStatus::Lost
122→            } else if bare == "none" {
123→                CommitStatus::None_
124→            } else {
125→                let issues = validate_ochid(
126→                    ochid_val,
127→                    &other_prefix,
128→                    args.id_len,
129→                    &other_workspace,
130→                    &other_repo,
131→                );
132→                if issues.any() {
133→                    CommitStatus::NeedsFixed(issues.summary())
134→                } else {
135→                    CommitStatus::Ok
136→                }
137→            }
138→        } else {
139→            match find_matching_commit(&commit, &other_workspace, &other_repo)? {
140→                TitleMatch::NoTitle => CommitStatus::MissingNoTitle,
141→                TitleMatch::One(id) => {
142→                    let short_id = &id[..id.len().min(args.id_len)];
143→                    CommitStatus::MissingWithMatch(format!("{other_prefix}{short_id}"))
144→                }
145→                TitleMatch::Ambiguous(n) => CommitStatus::MissingAmbiguous(n),
146→                TitleMatch::None => CommitStatus::MissingNoMatch,
147→            }
148→        };
149→
150→        match status {
151→            CommitStatus::Ok => {
152→                valid += 1;
153→                println!("ok   {change_short}  {display_title}");
154→            }
155→            CommitStatus::Lost => {
156→                lost += 1;
157→                println!("lost {change_short}  {display_title}");
158→            }
159→            CommitStatus::None_ => {
160→                none += 1;
161→                println!("none {change_short}  {display_title}");
162→            }
163→            CommitStatus::NeedsFixed(summary) => {
164→                issues_count += 1;
165→                println!("err  {change_short}  {display_title}  [{summary}]");
166→            }
167→            CommitStatus::MissingWithMatch(ochid) => {
168→                missing += 1;
169→                println!("miss {change_short}  {display_title}  [match: {ochid}]");
170→            }
171→            CommitStatus::MissingNoTitle => {
172→                missing += 1;
173→                println!("miss {change_short}  {display_title}");
174→            }
175→            CommitStatus::MissingAmbiguous(n) => {
176→                missing += 1;
177→                println!("miss {change_short}  {display_title}  [{n} title matches, ambiguous]");
178→            }
179→            CommitStatus::MissingNoMatch => {
180→                missing += 1;
181→                println!("miss {change_short}  {display_title}  [no matching title in other repo]");
182→            }
183→        }
184→    }
185→
186→    let total = valid + lost + none + issues_count + missing;
187→    if total > 10 {
188→        println!("{col_header}");
189→    }
190→    println!(
191→        "\n{valid} valid, {lost} lost, {none} none, {issues_count} issues, {missing} missing (of {} total)",
192→        ids.len()
193→    );
194→    if issues_count > 0 {
195→        Err(format!("{issues_count} commit(s) have issues").into())
196→    } else {
197→        Ok(())
198→    }
199→}
