 16→/// Fix commit descriptions against the other repo.
 17→#[derive(Args, Debug)]
 18→pub struct FixDescArgs {
 19→    /// Revision (with optional .. notation)
 20→    #[arg(value_name = "REVISION")]
 21→    pub pos_rev: Option<String>,
 22→
 23→    /// Number of commits (per dotted side)
 24→    #[arg(value_name = "COMMITS")]
 25→    pub pos_count: Option<usize>,
 26→
 27→    /// Revision(s) to scan
 28→    #[arg(short, long, default_value = "@")]
 29→    pub revision: String,
 30→
 31→    /// Number of commits to scan
 32→    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
 33→    pub limit: Option<usize>,
 34→
 35→    /// Maximum number of commits to actually fix/change [default: all]
 36→    #[arg(short = 'm', long = "max-fixes")]
 37→    pub max_fixes: Option<usize>,
 38→
 39→    /// Path to jj repo
 40→    #[arg(short = 'R', long, default_value = ".")]
 41→    pub repo: PathBuf,
 42→
 43→    /// Path to the other repo [default: from .vc-config.toml]
 44→    #[arg(long = "other-repo")]
 45→    pub other_repo: Option<PathBuf>,
 46→
 47→    /// Expected changeID length
 48→    #[arg(long = "id-len", default_value_t = DEFAULT_ID_LEN)]
 49→    pub id_len: usize,
 50→
 51→    /// New title to replace the first line (optional)
 52→    #[arg(long)]
 53→    pub title: Option<String>,
 54→
 55→    /// Fallback ochid value for IDs not found in other repo (e.g. /.claude/lost)
 56→    #[arg(long)]
 57→    pub fallback: Option<String>,
 58→
 59→    /// Actually write changes [default: dry-run]
 60→    #[arg(long = "no-dry-run")]
 61→    pub no_dry_run: bool,
 62→
 63→    /// Add missing ochid trailers by matching title and timestamp
 64→    #[arg(long = "add-missing")]
 65→    pub add_missing: bool,
