 68→pub fn fix_desc(args: &FixDescArgs) -> Result<(), Box<dyn std::error::Error>> {
 69→    let (workspace, repo) = common::load_repo(&args.repo)?;
 70→
 71→    // Resolve other repo: --other-repo flag, or fall back to .vc-config.toml
 72→    let other_repo_path = if let Some(ref p) = args.other_repo {
 73→        p.clone()
 74→    } else {
 75→        let config = toml_simple::toml_load(&args.repo.join(VC_CONFIG_FILE))?;
 76→        PathBuf::from(other_repo_from_config(&config)?)
 77→    };
 78→
 79→    let (other_workspace, other_repo) = common::load_repo(&other_repo_path)?;
 80→    let other_config = toml_simple::toml_load(&other_repo_path.join(VC_CONFIG_FILE))?;
 81→    let other_prefix = ochid_prefix_from_config(&other_config)?;
 82→
 83→    let spec = common::resolve_spec(
 84→        args.pos_rev.as_deref(),
 85→        args.pos_count,
 86→        &args.revision,
 87→        args.limit,
 88→        "@",
 89→    );
 90→
 91→    let (ids, _anchor_index) = common::collect_ids(
 92→        &workspace,
 93→        &repo,
 94→        &spec.rev,
 95→        spec.desc_count,
 96→        spec.anc_count,
 97→    )?;
 98→    if ids.is_empty() {
 99→        return Err(format!("no commits found for revision '{}'", args.revision).into());
100→    }
101→
102→    let root_id = repo.store().root_commit_id().clone();
103→    let mut fixed = 0;
104→    let mut skipped = 0;
105→    let mut errors = 0;
106→
107→    for commit_id in &ids {
108→        if *commit_id == root_id {
109→            continue;
110→        }
111→        let commit = repo.store().get_commit(commit_id)?;
112→        let desc = commit.description();
113→        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
114→        let change_short = &change_hex[..change_hex.len().min(12)];
115→        let first_line = desc.lines().next().unwrap_or("");
116→        let display_title = if first_line.is_empty() {
117→            "(no description set)"
118→        } else {
119→            first_line
120→        };
121→
122→        // Extract current ochid value
123→        let current_ochid = common::extract_ochid(&commit);
124→
125→        // Validate current ochid
126→        let issues = if let Some(ref ochid_val) = current_ochid {
127→            validate_ochid(
128→                ochid_val,
129→                &other_prefix,
130→                args.id_len,
131→                &other_workspace,
132→                &other_repo,
133→            )
134→        } else if args.add_missing {
135→            // Stop if we've hit the max-fixes limit
136→            if let Some(max) = args.max_fixes
137→                && fixed >= max
138→            {
139→                skipped += 1;
140→                if !args.no_dry_run {
141→                    println!("skip {change_short}  {display_title}  (max-fixes reached)");
142→                }
143→                continue;
144→            }
145→            // No ochid trailer — try to infer from the other repo
146→            match find_matching_commit(&commit, &other_workspace, &other_repo)? {
147→                TitleMatch::NoTitle => {
148→                    skipped += 1;
149→                    if !args.no_dry_run {
150→                        println!("skip {change_short}  {display_title}");
151→                    }
152→                    continue;
153→                }
154→                TitleMatch::One(matched_id) => {
155→                    let new_desc =
156→                        append_ochid_trailer(desc, &other_prefix, &matched_id, args.id_len);
157→                    let short_matched = &matched_id[..matched_id.len().min(args.id_len)];
158→                    if !args.no_dry_run {
159→                        println!("add  {change_short}  {display_title}  [missing]");
160→                        println!("     -> ochid: {other_prefix}{short_matched}");
161→                    } else {
162→                        jj_describe(commit_id, &new_desc, &args.repo, change_short)?;
163→                        println!("added {change_short}  {display_title}");
164→                    }
165→                    fixed += 1;
166→                    continue;
167→                }
168→                TitleMatch::Ambiguous(n) => {
169→                    skipped += 1;
170→                    if !args.no_dry_run {
171→                        println!(
172→                            "skip {change_short}  {display_title}  ({n} title matches, ambiguous)"
173→                        );
174→                    }
175→                    continue;
176→                }
177→                TitleMatch::None => {
178→                    skipped += 1;
179→                    if !args.no_dry_run {
180→                        println!(
181→                            "skip {change_short}  {display_title}  (no matching title in other repo)"
182→                        );
183→                    }
184→                    continue;
185→                }
186→            }
187→        } else {
188→            // No ochid trailer — nothing to fix
189→            skipped += 1;
190→            if !args.no_dry_run {
191→                println!("skip {change_short}  {display_title}  (no ochid trailer)");
192→            }
193→            continue;
194→        };
195→
196→        if !issues.any() {
197→            skipped += 1;
198→            if !args.no_dry_run {
199→                println!("ok   {change_short}  {display_title}");
200→            }
201→            continue;
202→        }
203→
204→        // Stop if we've hit the max-fixes limit
205→        if let Some(max) = args.max_fixes
206→            && fixed >= max
207→        {
208→            skipped += 1;
209→            if !args.no_dry_run {
210→                println!("skip {change_short}  {display_title}  (max-fixes reached)");
211→            }
212→            continue;
213→        }
214→
215→        // Resolve the full change ID from the other repo when length is wrong
216→        let resolved_id = if issues.wrong_length.is_some() {
217→            let ochid_val = current_ochid.as_deref().unwrap_or("");
218→            let bare_id = extract_bare_id(ochid_val);
219→            resolve_full_change_id(bare_id, &other_workspace, &other_repo)?
220→        } else {
221→            None
222→        };
223→
224→        // Build the fixed description
225→        let mut new_desc = fix_ochid_in_description(
226→            desc,
227→            &other_prefix,
228→            args.id_len,
229→            args.title.as_deref(),
230→            resolved_id.as_deref(),
231→        );
232→
233→        // Re-extract the fixed ochid value for post-validation
234→        let mut fixed_ochid = extract_ochid_from_desc(&new_desc);
235→
236→        let post_issues = if let Some(ref v) = fixed_ochid {
237→            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
238→        } else {
239→            OchidIssues {
240→                wrong_prefix: None,
241→                wrong_length: None,
242→                not_found: true,
243→                bare_id: String::new(),
244→            }
245→        };
246→
247→        if post_issues.not_found {
248→            if let Some(ref fallback) = args.fallback {
249→                // Replace the ochid line with the fallback value
250→                let mut fb_lines: Vec<String> = new_desc.lines().map(|l| l.to_string()).collect();
251→                for line in &mut fb_lines {
252→                    if line.trim().starts_with("ochid:") {
253→                        *line = format!("ochid: {fallback}");
254→                    }
255→                }
256→                let fb_desc = if new_desc.ends_with('\n') {
257→                    format!("{}\n", fb_lines.join("\n"))
258→                } else {
259→                    fb_lines.join("\n")
260→                };
261→                new_desc = fb_desc;
262→                fixed_ochid = Some(fallback.clone());
263→            } else {
264→                errors += 1;
265→                eprintln!(
266→                    "err  {change_short}  {display_title}  (ID not found, ochid: {})",
267→                    fixed_ochid.as_deref().unwrap_or("?")
268→                );
269→                continue;
270→            }
271→        }
272→
273→        if !args.no_dry_run {
274→            println!(
275→                "fix  {change_short}  {display_title}  [{}]",
276→                issues.summary()
277→            );
278→            if let Some(ref v) = fixed_ochid {
279→                println!("     -> ochid: {v}");
280→            }
281→        } else {
282→            jj_describe(commit_id, &new_desc, &args.repo, change_short)?;
283→            let fixed_title = new_desc.lines().next().unwrap_or("");
284→            println!("fixed {change_short}  {fixed_title}");
285→        }
286→        fixed += 1;
287→    }
288→
289→    println!(
290→        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
291→        ids.len()
292→    );
293→    if errors > 0 {
294→        Err(format!("{errors} commit(s) could not be fixed").into())
295→    } else {
296→        Ok(())
297→    }
298→}
299→
300→/// Run `jj describe` to rewrite a commit's description.
301→fn jj_describe(
302→    commit_id: &jj_lib::backend::CommitId,
303→    new_desc: &str,
304→    repo_path: &std::path::Path,
305→    change_short: &str,
306→) -> Result<(), Box<dyn std::error::Error>> {
307→    let status = Command::new("jj")
308→        .arg("describe")
309→        .arg("-m")
310→        .arg(new_desc)
311→        .arg("-r")
312→        .arg(commit_id.hex())
313→        .arg("-R")
314→        .arg(repo_path)
315→        .arg("--ignore-immutable")
316→        .stdout(std::process::Stdio::null())
317→        .stderr(std::process::Stdio::inherit())
318→        .status()?;
319→    if !status.success() {
320→        return Err(format!(
321→            "jj describe failed for {} (exit {})",
322→            change_short,
323→            status.code().unwrap_or(-1)
324→        )
325→        .into());
326→    }
327→    Ok(())
328→}
