 14→/// Read the other repo path from a repo's `.vc-config.toml`.
 15→///
 16→/// Returns the `workspace.other-repo` value, which is the relative path
 17→/// to the counterpart repo from the repo's directory.
 18→pub fn other_repo_from_config(
 19→    config: &HashMap<String, String>,
 20→) -> Result<String, Box<dyn std::error::Error>> {
 21→    toml_simple::toml_get(config, "workspace.other-repo")
 22→        .cloned()
 23→        .ok_or_else(|| "missing workspace.other-repo in .vc-config.toml".into())
 24→}
 25→
 26→/// Derive the ochid prefix from a repo's `.vc-config.toml`.
 27→///
 28→/// The `workspace.path` value is the repo's path relative to the workspace
 29→/// root, which is exactly the ochid prefix (with a trailing `/` when the
 30→/// path isn't just `/`).
 31→pub fn ochid_prefix_from_config(
 32→    config: &HashMap<String, String>,
 33→) -> Result<String, Box<dyn std::error::Error>> {
 34→    let ws_path = toml_simple::toml_get(config, "workspace.path")
 35→        .ok_or("missing workspace.path in .vc-config.toml")?;
 36→    let trimmed = ws_path.trim_end_matches('/');
 37→    if trimmed.is_empty() {
 38→        Ok("/".to_string())
 39→    } else {
 40→        Ok(format!("{trimmed}/"))
 41→    }
 42→}
