179→/// Extract the bare change ID from an ochid value (strip path prefix).
180→pub fn extract_bare_id(ochid_value: &str) -> &str {
181→    if let Some(pos) = ochid_value.rfind('/') {
182→        &ochid_value[pos + 1..]
183→    } else {
184→        ochid_value
185→    }
186→}
