188→/// Fix the ochid trailer in a commit description.
189→///
190→/// If `resolved_id` is provided, it replaces the bare changeID entirely
191→/// (used when the existing ID is too short to extend by truncation alone).
192→pub fn fix_ochid_in_description(
193→    desc: &str,
194→    other_prefix: &str,
195→    id_len: usize,
196→    new_title: Option<&str>,
197→    resolved_id: Option<&str>,
198→) -> String {
199→    let mut lines: Vec<String> = desc.lines().map(|l| l.to_string()).collect();
200→
201→    // Fix title if requested
202→    if let Some(title) = new_title
203→        && !lines.is_empty()
204→    {
205→        lines[0] = title.to_string();
206→    }
207→
208→    // Fix ochid trailer
209→    for line in &mut lines {
210→        let trimmed = line.trim();
211→        if let Some(value) = trimmed.strip_prefix("ochid:") {
212→            let value = value.trim();
213→            let id = if let Some(rid) = resolved_id {
214→                &rid[..rid.len().min(id_len)]
215→            } else {
216→                let bare_id = extract_bare_id(value);
217→                &bare_id[..bare_id.len().min(id_len)]
218→            };
219→            *line = format!("ochid: {other_prefix}{id}");
220→        }
221→    }
222→
223→    // Preserve trailing newline if original had one
224→    let mut result = lines.join("\n");
225→    if desc.ends_with('\n') {
226→        result.push('\n');
227→    }
228→    result
229→}
230→
231→/// Append an ochid trailer to a commit description.
232→pub fn append_ochid_trailer(
233→    desc: &str,
234→    other_prefix: &str,
235→    change_id: &str,
236→    id_len: usize,
237→) -> String {
238→    let short_id = &change_id[..change_id.len().min(id_len)];
239→    let trailer = format!("ochid: {other_prefix}{short_id}");
240→
241→    let mut result = desc.trim_end().to_string();
242→    // Add blank line before trailer if body exists, otherwise just newline
243→    if result.lines().count() > 1 {
244→        result.push('\n');
245→    } else {
246→        result.push_str("\n\n");
247→    }
248→    result.push_str(&trailer);
249→    result.push('\n');
250→    result
251→}
252→
253→/// Extract the ochid value from a description string (without needing a Commit).
254→pub fn extract_ochid_from_desc(desc: &str) -> Option<String> {
255→    for line in desc.lines() {
256→        let trimmed = line.trim();
257→        if let Some(v) = trimmed.strip_prefix("ochid:") {
258→            return Some(v.trim().to_string());
259→        }
260→    }
261→    None
262→}
