173→/// Indent all lines after the first by `n` spaces.
174→///
175→/// Returns the string unchanged if `n == 0` or there is only one line.
176→pub fn indent_body(s: &str, n: usize) -> String {
177→    if n == 0 {
178→        return s.to_string();
179→    }
180→    let pad = " ".repeat(n);
181→    let mut lines = s.lines();
182→    let mut result = match lines.next() {
183→        Some(first) => first.to_string(),
184→        None => return String::new(),
185→    };
186→    for line in lines {
187→        result.push('\n');
188→        if !line.is_empty() {
189→            result.push_str(&pad);
190→        }
191→        result.push_str(line);
192→    }
193→    result
194→}
