use std::path::PathBuf;

use clap::Args;
use jj_lib::object_id::ObjectId;
use jj_lib::repo::Repo;

use crate::common;
use crate::desc_helpers::{
    DEFAULT_ID_LEN, TitleMatch, VC_CONFIG_FILE, extract_bare_id, find_matching_commit,
    ochid_prefix_from_config, other_repo_from_config, validate_ochid,
};
use crate::toml_simple;

#[derive(Args, Debug)]
pub struct ValidateDescArgs {
    /// Revision (with optional .. notation)
    #[arg(value_name = "REVISION")]
    pub pos_rev: Option<String>,

    /// Number of commits (per dotted side)
    #[arg(value_name = "COMMITS")]
    pub pos_count: Option<usize>,

    /// Revision(s) to scan
    #[arg(short, long, default_value = "@")]
    pub revision: String,

    /// Number of commits to scan
    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
    pub limit: Option<usize>,

    /// Path to jj repo
    #[arg(short = 'R', long, default_value = ".")]
    pub repo: PathBuf,

    /// Path to the other repo [default: from .vc-config.toml]
    #[arg(long = "other-repo")]
    pub other_repo: Option<PathBuf>,

    /// Expected changeID length
    #[arg(long = "id-len", default_value_t = DEFAULT_ID_LEN)]
    pub id_len: usize,
}

/// Status of a single commit's ochid validation.
enum CommitStatus {
    Ok,
    Lost,                     // ochid marked as "lost" (unrecoverable)
    None_,                    // ochid marked as "none" (no counterpart)
    NeedsFixed(String),       // summary of issues
    MissingNoTitle,           // no ochid, no title to match on
    MissingNoMatch,           // no ochid, no title match in other repo
    MissingAmbiguous(usize),  // no ochid, multiple title matches
    MissingWithMatch(String), // no ochid, unique title match found
}

pub fn validate_desc(args: &ValidateDescArgs) -> Result<(), Box<dyn std::error::Error>> {
    let (workspace, repo) = common::load_repo(&args.repo)?;

    // Resolve other repo: --other-repo flag, or fall back to .vc-config.toml
    let other_repo_path = if let Some(ref p) = args.other_repo {
        p.clone()
    } else {
        let config = toml_simple::toml_load(&args.repo.join(VC_CONFIG_FILE))?;
        PathBuf::from(other_repo_from_config(&config)?)
    };

    let (other_workspace, other_repo) = common::load_repo(&other_repo_path)?;
    let other_config = toml_simple::toml_load(&other_repo_path.join(VC_CONFIG_FILE))?;
    let other_prefix = ochid_prefix_from_config(&other_config)?;

    let spec = common::resolve_spec(
        args.pos_rev.as_deref(),
        args.pos_count,
        &args.revision,
        args.limit,
        "@",
    );

    let (ids, _anchor_index) = common::collect_ids(
        &workspace,
        &repo,
        &spec.rev,
        spec.desc_count,
        spec.anc_count,
    )?;
    if ids.is_empty() {
        return Err(format!("no commits found for revision '{}'", args.revision).into());
    }

    let root_id = repo.store().root_commit_id().clone();
    let mut valid = 0;
    let mut lost = 0;
    let mut none = 0;
    let mut issues_count = 0;
    let mut missing = 0;

    let col_header = "STAT CHANGEID      TITLE";
    println!("{col_header}");

    for commit_id in &ids {
        if *commit_id == root_id {
            continue;
        }
        let commit = repo.store().get_commit(commit_id)?;
        let desc = commit.description();
        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
        let change_short = &change_hex[..change_hex.len().min(12)];
        let first_line = desc.lines().next().unwrap_or("");
        let display_title = if first_line.is_empty() {
            "(no description set)"
        } else {
            first_line
        };

        let current_ochid = common::extract_ochid(&commit);

        let status = if let Some(ref ochid_val) = current_ochid {
            let bare = extract_bare_id(ochid_val);
            if bare == "lost" {
                CommitStatus::Lost
            } else if bare == "none" {
                CommitStatus::None_
            } else {
                let issues = validate_ochid(
                    ochid_val,
                    &other_prefix,
                    args.id_len,
                    &other_workspace,
                    &other_repo,
                );
                if issues.any() {
                    CommitStatus::NeedsFixed(issues.summary())
                } else {
                    CommitStatus::Ok
                }
            }
        } else {
            match find_matching_commit(&commit, &other_workspace, &other_repo)? {
                TitleMatch::NoTitle => CommitStatus::MissingNoTitle,
                TitleMatch::One(id) => {
                    let short_id = &id[..id.len().min(args.id_len)];
                    CommitStatus::MissingWithMatch(format!("{other_prefix}{short_id}"))
                }
                TitleMatch::Ambiguous(n) => CommitStatus::MissingAmbiguous(n),
                TitleMatch::None => CommitStatus::MissingNoMatch,
            }
        };

        match status {
            CommitStatus::Ok => {
                valid += 1;
                println!("ok   {change_short}  {display_title}");
            }
            CommitStatus::Lost => {
                lost += 1;
                println!("lost {change_short}  {display_title}");
            }
            CommitStatus::None_ => {
                none += 1;
                println!("none {change_short}  {display_title}");
            }
            CommitStatus::NeedsFixed(summary) => {
                issues_count += 1;
                println!("err  {change_short}  {display_title}  [{summary}]");
            }
            CommitStatus::MissingWithMatch(ochid) => {
                missing += 1;
                println!("miss {change_short}  {display_title}  [match: {ochid}]");
            }
            CommitStatus::MissingNoTitle => {
                missing += 1;
                println!("miss {change_short}  {display_title}");
            }
            CommitStatus::MissingAmbiguous(n) => {
                missing += 1;
                println!("miss {change_short}  {display_title}  [{n} title matches, ambiguous]");
            }
            CommitStatus::MissingNoMatch => {
                missing += 1;
                println!("miss {change_short}  {display_title}  [no matching title in other repo]");
            }
        }
    }

    let total = valid + lost + none + issues_count + missing;
    if total > 10 {
        println!("{col_header}");
    }
    println!(
        "\n{valid} valid, {lost} lost, {none} none, {issues_count} issues, {missing} missing (of {} total)",
        ids.len()
    );
    if issues_count > 0 {
        Err(format!("{issues_count} commit(s) have issues").into())
    } else {
        Ok(())
    }
}

use std::path::PathBuf;
use std::process::Command;

use clap::Args;
use jj_lib::object_id::ObjectId;
use jj_lib::repo::Repo;

use crate::common;
use crate::desc_helpers::{
    DEFAULT_ID_LEN, OchidIssues, TitleMatch, VC_CONFIG_FILE, append_ochid_trailer, extract_bare_id,
    extract_ochid_from_desc, find_matching_commit, fix_ochid_in_description,
    ochid_prefix_from_config, other_repo_from_config, resolve_full_change_id, validate_ochid,
};
use crate::toml_simple;

/// Fix commit descriptions against the other repo.
#[derive(Args, Debug)]
pub struct FixDescArgs {
    /// Revision (with optional .. notation)
    #[arg(value_name = "REVISION")]
    pub pos_rev: Option<String>,

    /// Number of commits (per dotted side)
    #[arg(value_name = "COMMITS")]
    pub pos_count: Option<usize>,

    /// Revision(s) to scan
    #[arg(short, long, default_value = "@")]
    pub revision: String,

    /// Number of commits to scan
    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
    pub limit: Option<usize>,

    /// Maximum number of commits to actually fix/change [default: all]
    #[arg(short = 'm', long = "max-fixes")]
    pub max_fixes: Option<usize>,

    /// Path to jj repo
    #[arg(short = 'R', long, default_value = ".")]
    pub repo: PathBuf,

    /// Path to the other repo [default: from .vc-config.toml]
    #[arg(long = "other-repo")]
    pub other_repo: Option<PathBuf>,

    /// Expected changeID length
    #[arg(long = "id-len", default_value_t = DEFAULT_ID_LEN)]
    pub id_len: usize,

    /// New title to replace the first line (optional)
    #[arg(long)]
    pub title: Option<String>,

    /// Fallback ochid value for IDs not found in other repo (e.g. /.claude/lost)
    #[arg(long)]
    pub fallback: Option<String>,

    /// Actually write changes [default: dry-run]
    #[arg(long = "no-dry-run")]
    pub no_dry_run: bool,

    /// Add missing ochid trailers by matching title and timestamp
    #[arg(long = "add-missing")]
    pub add_missing: bool,
}

pub fn fix_desc(args: &FixDescArgs) -> Result<(), Box<dyn std::error::Error>> {
    let (workspace, repo) = common::load_repo(&args.repo)?;

    // Resolve other repo: --other-repo flag, or fall back to .vc-config.toml
    let other_repo_path = if let Some(ref p) = args.other_repo {
        p.clone()
    } else {
        let config = toml_simple::toml_load(&args.repo.join(VC_CONFIG_FILE))?;
        PathBuf::from(other_repo_from_config(&config)?)
    };

    let (other_workspace, other_repo) = common::load_repo(&other_repo_path)?;
    let other_config = toml_simple::toml_load(&other_repo_path.join(VC_CONFIG_FILE))?;
    let other_prefix = ochid_prefix_from_config(&other_config)?;

    let spec = common::resolve_spec(
        args.pos_rev.as_deref(),
        args.pos_count,
        &args.revision,
        args.limit,
        "@",
    );

    let (ids, _anchor_index) = common::collect_ids(
        &workspace,
        &repo,
        &spec.rev,
        spec.desc_count,
        spec.anc_count,
    )?;
    if ids.is_empty() {
        return Err(format!("no commits found for revision '{}'", args.revision).into());
    }

    let root_id = repo.store().root_commit_id().clone();
    let mut fixed = 0;
    let mut skipped = 0;
    let mut errors = 0;

    for commit_id in &ids {
        if *commit_id == root_id {
            continue;
        }
        let commit = repo.store().get_commit(commit_id)?;
        let desc = commit.description();
        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
        let change_short = &change_hex[..change_hex.len().min(12)];
        let first_line = desc.lines().next().unwrap_or("");
        let display_title = if first_line.is_empty() {
            "(no description set)"
        } else {
            first_line
        };

        // Extract current ochid value
        let current_ochid = common::extract_ochid(&commit);

        // Validate current ochid
        let issues = if let Some(ref ochid_val) = current_ochid {
            validate_ochid(
                ochid_val,
                &other_prefix,
                args.id_len,
                &other_workspace,
                &other_repo,
            )
        } else if args.add_missing {
            // Stop if we've hit the max-fixes limit
            if let Some(max) = args.max_fixes
                && fixed >= max
            {
                skipped += 1;
                if !args.no_dry_run {
                    println!("skip {change_short}  {display_title}  (max-fixes reached)");
                }
                continue;
            }
            // No ochid trailer — try to infer from the other repo
            match find_matching_commit(&commit, &other_workspace, &other_repo)? {
                TitleMatch::NoTitle => {
                    skipped += 1;
                    if !args.no_dry_run {
                        println!("skip {change_short}  {display_title}");
                    }
                    continue;
                }
                TitleMatch::One(matched_id) => {
                    let new_desc =
                        append_ochid_trailer(desc, &other_prefix, &matched_id, args.id_len);
                    let short_matched = &matched_id[..matched_id.len().min(args.id_len)];
                    if !args.no_dry_run {
                        println!("add  {change_short}  {display_title}  [missing]");
                        println!("     -> ochid: {other_prefix}{short_matched}");
                    } else {
                        jj_describe(commit_id, &new_desc, &args.repo, change_short)?;
                        println!("added {change_short}  {display_title}");
                    }
                    fixed += 1;
                    continue;
                }
                TitleMatch::Ambiguous(n) => {
                    skipped += 1;
                    if !args.no_dry_run {
                        println!(
                            "skip {change_short}  {display_title}  ({n} title matches, ambiguous)"
                        );
                    }
                    continue;
                }
                TitleMatch::None => {
                    skipped += 1;
                    if !args.no_dry_run {
                        println!(
                            "skip {change_short}  {display_title}  (no matching title in other repo)"
                        );
                    }
                    continue;
                }
            }
        } else {
            // No ochid trailer — nothing to fix
            skipped += 1;
            if !args.no_dry_run {
                println!("skip {change_short}  {display_title}  (no ochid trailer)");
            }
            continue;
        };

        if !issues.any() {
            skipped += 1;
            if !args.no_dry_run {
                println!("ok   {change_short}  {display_title}");
            }
            continue;
        }

        // Stop if we've hit the max-fixes limit
        if let Some(max) = args.max_fixes
            && fixed >= max
        {
            skipped += 1;
            if !args.no_dry_run {
                println!("skip {change_short}  {display_title}  (max-fixes reached)");
            }
            continue;
        }

        // Resolve the full change ID from the other repo when length is wrong
        let resolved_id = if issues.wrong_length.is_some() {
            let ochid_val = current_ochid.as_deref().unwrap_or("");
            let bare_id = extract_bare_id(ochid_val);
            resolve_full_change_id(bare_id, &other_workspace, &other_repo)?
        } else {
            None
        };

        // Build the fixed description
        let mut new_desc = fix_ochid_in_description(
            desc,
            &other_prefix,
            args.id_len,
            args.title.as_deref(),
            resolved_id.as_deref(),
        );

        // Re-extract the fixed ochid value for post-validation
        let mut fixed_ochid = extract_ochid_from_desc(&new_desc);

        let post_issues = if let Some(ref v) = fixed_ochid {
            validate_ochid(v, &other_prefix, args.id_len, &other_workspace, &other_repo)
        } else {
            OchidIssues {
                wrong_prefix: None,
                wrong_length: None,
                not_found: true,
                bare_id: String::new(),
            }
        };

        if post_issues.not_found {
            if let Some(ref fallback) = args.fallback {
                // Replace the ochid line with the fallback value
                let mut fb_lines: Vec<String> = new_desc.lines().map(|l| l.to_string()).collect();
                for line in &mut fb_lines {
                    if line.trim().starts_with("ochid:") {
                        *line = format!("ochid: {fallback}");
                    }
                }
                let fb_desc = if new_desc.ends_with('\n') {
                    format!("{}\n", fb_lines.join("\n"))
                } else {
                    fb_lines.join("\n")
                };
                new_desc = fb_desc;
                fixed_ochid = Some(fallback.clone());
            } else {
                errors += 1;
                eprintln!(
                    "err  {change_short}  {display_title}  (ID not found, ochid: {})",
                    fixed_ochid.as_deref().unwrap_or("?")
                );
                continue;
            }
        }

        if !args.no_dry_run {
            println!(
                "fix  {change_short}  {display_title}  [{}]",
                issues.summary()
            );
            if let Some(ref v) = fixed_ochid {
                println!("     -> ochid: {v}");
            }
        } else {
            jj_describe(commit_id, &new_desc, &args.repo, change_short)?;
            let fixed_title = new_desc.lines().next().unwrap_or("");
            println!("fixed {change_short}  {fixed_title}");
        }
        fixed += 1;
    }

    println!(
        "\n{fixed} fixed, {skipped} skipped, {errors} errors (of {} total)",
        ids.len()
    );
    if errors > 0 {
        Err(format!("{errors} commit(s) could not be fixed").into())
    } else {
        Ok(())
    }
}

/// Run `jj describe` to rewrite a commit's description.
fn jj_describe(
    commit_id: &jj_lib::backend::CommitId,
    new_desc: &str,
    repo_path: &std::path::Path,
    change_short: &str,
) -> Result<(), Box<dyn std::error::Error>> {
    let status = Command::new("jj")
        .arg("describe")
        .arg("-m")
        .arg(new_desc)
        .arg("-r")
        .arg(commit_id.hex())
        .arg("-R")
        .arg(repo_path)
        .arg("--ignore-immutable")
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::inherit())
        .status()?;
    if !status.success() {
        return Err(format!(
            "jj describe failed for {} (exit {})",
            change_short,
            status.code().unwrap_or(-1)
        )
        .into());
    }
    Ok(())
}
